import { makeStyles } from '@material-ui/core/styles';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableContainer from '@material-ui/core/TableContainer';
import TableHead from '@material-ui/core/TableHead';
import TableRow from '@material-ui/core/TableRow';
import Paper from '@material-ui/core/Paper';
import { Box } from '@material-ui/core';

const useStyles = makeStyles({
    table: {
        minWidth: 650,
    },
});

const TableResult = (props) => {
    const classes = useStyles();


    const products = props.data.products;


    return (
        <TableContainer component={Paper}>
            <Table className={classes.table} aria-label="simple table">
                <TableHead>
                    <TableRow>
                        <TableCell><Box fontWeight="fontWeightBold" m={1}>
                            Title
      </Box></TableCell>
                        <TableCell align="center">Asin</TableCell>
                        <TableCell align="center">Price</TableCell>
                        <TableCell align="center">Rating</TableCell>
                        <TableCell align="center">Total Reviews</TableCell>
                        <TableCell align="center">Amazon Choice</TableCell>
                        <TableCell align="center">Amazon Prime</TableCell>
                        <TableCell align="center">Best Seller</TableCell>
                        <TableCell align="center">Sponsored</TableCell>
                        <TableCell align="center">Image</TableCell>

                    </TableRow>
                </TableHead>

                <TableBody>
                    {products.map((product) => (
                        <TableRow>
                            <TableCell component="th" scope="row">
                                {product.title}
                            </TableCell>
                            <TableCell align="right">{product.asin}</TableCell>
                            <TableCell align="right">{product.price.current_price}</TableCell>
                            <TableCell align="right">{product.reviews.rating}</TableCell>
                            <TableCell align="right">{product.reviews.total_reviews}</TableCell>
                            <TableCell align="right">{product.amazonChoice ? (<p>Yes</p>) : (<p>No</p>)}</TableCell>
                            <TableCell align="right">{product.amazonPrime ? (<p>Yes</p>) : (<p>No</p>)}</TableCell>
                            <TableCell align="right">{product.BestSeller ? (<p>Yes</p>) : (<p>No</p>)}</TableCell>
                            <TableCell align="right">{product.sponsored ? (<p>Yes</p>) : (<p>No</p>)}</TableCell>
                            <TableCell align="right"><img src={product.thumbnail} alt="" width="50" height="80" /></TableCell>
                        </TableRow>
                    ))}
                </TableBody>

            </Table>

        </TableContainer>
        // <div>
        //     <li>
        //         {products.map((product) => (
        //             <ul>{product.title} {product.asin} {product.price}{product.rating}{product.total_reviews}{product.amazonChoice}{product.amazonPrime}{product.bestSeller}{product.sponsored}</ul>
        //         ))}
        //     </li>
        // </div>
    );
}

export default TableResult;
